// ── Helper functions ────────────────────────────────────────────

func stateLabel(state string) string {
	switch state {
	case StateOpen:
		return "Open"
	case StateActive:
		return "Active"
	case StateReview:
		return "Review"
	case StateDone:
		return "Done"
	case StateClosed:
		return "Closed"
	default:
		return state
	}
}

func stateBgClass(state string) string {
	switch state {
	case StateOpen:
		return "bg-warm-faint/20 text-warm-muted"
	case StateActive:
		return "bg-indigo-500/15 text-indigo-400"
	case StateReview:
		return "bg-amber-500/15 text-amber-400"
	case StateDone:
		return "bg-emerald-500/15 text-emerald-400"
	case StateClosed:
		return "bg-warm-faint/20 text-warm-faint"
	default:
		return "bg-warm-faint/20 text-warm-muted"
	}
}

func stateColorHex(state string) string {
	switch state {
	case StateOpen:
		return "#78756e"
	case StateActive:
		return "#818cf8"
	case StateReview:
		return "#fbbf24"
	case StateDone:
		return "#6ec89b"
	case StateClosed:
		return "#4a4844"
	default:
		return "#78756e"
	}
}

func priorityDotHex(priority string) string {
	switch priority {
	case PriorityUrgent:
		return "#e07070"
	case PriorityHigh:
		return "#fbbf24"
	case PriorityMedium:
		return "#e8a0b8"
	case PriorityLow:
		return "#78756e"
	default:
		return "#78756e"
	}
}

func boardEmpty(columns []BoardColumn) bool {
	for _, col := range columns {
		if len(col.Nodes) > 0 {
			return false
		}
	}
	return true
}

func dashboardStateClass(state string) string {
	switch state {
	case StateOpen:
		return "bg-warm-faint/20 text-warm-muted"
	case StateActive:
		return "bg-indigo-500/15 text-indigo-400"
	case StateReview:
		return "bg-amber-500/15 text-amber-400"
	default:
		return "bg-warm-faint/20 text-warm-muted"
	}
}

func dashRelativeTime(t time.Time) string {
	d := time.Since(t)
	switch {
	case d < time.Minute:
		return "now"
	case d < time.Hour:
		return fmt.Sprintf("%dm", int(d.Minutes()))
	case d < 24*time.Hour:
		return fmt.Sprintf("%dh", int(d.Hours()))
	case d < 30*24*time.Hour:
		return fmt.Sprintf("%dd", int(d.Hours()/24))
	default:
		return t.Format("Jan 2")
	}
}

func truncateBody(s string, maxLen int) string {
	if len(s) <= maxLen {
		return s
	}
	return s[:maxLen] + "..."
}

func kindBadgeClass(kind string) string {
	switch kind {
	case KindTask, SpaceProject:
		return "bg-indigo-500/15 text-indigo-400"
	case KindPost, SpaceCommunity:
		return "bg-emerald-500/15 text-emerald-400"
	case KindThread, SpaceTeam:
		return "bg-amber-500/15 text-amber-400"
	case KindComment:
		return "bg-warm-faint/20 text-warm-muted"
	default:
		return "bg-warm-faint/20 text-warm-muted"
	}
}

func opBadgeClass(op string) string {
	switch op {
	case "intend", "decompose":
		return "bg-indigo-500/15 text-indigo-400"
	case "express", "discuss":
		return "bg-emerald-500/15 text-emerald-400"
	case "respond":
		return "bg-warm-faint/20 text-warm-muted"
	case "complete":
		return "bg-emerald-500/15 text-emerald-400"
	case "claim", "assign":
		return "bg-amber-500/15 text-amber-400"
	case "prioritize":
		return "bg-purple-500/15 text-purple-400"
	case "review":
		return "bg-amber-500/15 text-amber-400"
	case "progress":
		return "bg-blue-500/15 text-blue-400"
	default:
		return "bg-warm-faint/20 text-warm-muted"
	}
}

func renderMarkdown(src string) templ.Component {
	var buf bytes.Buffer
	md := goldmark.New()
	if err := md.Convert([]byte(src), &buf); err != nil {
		return templ.Raw("<p>" + src + "</p>")
	}
	return templ.Raw(buf.String())
}

func resolveName(id string, nameMap map[string]string) string {
	if nameMap != nil {
		if name, ok := nameMap[id]; ok {
			return name
		}
	}
	return id
}

func initial(name string) string {
	if name == "" {
		return ""
	}
	runes := []rune(name)
	if len(runes) == 0 {
		return ""
	}
	return string(runes[0:1])
}

func childProgress(node Node) string {
	if node.ChildCount == 0 {
		return "width: 0%"
	}
	pct := (node.ChildDone * 100) / node.ChildCount
	return fmt.Sprintf("width: %d%%", pct)
}

func childProgressSlice(nodes []Node) string {
	if len(nodes) == 0 {
		return "width: 0%"
	}
	done := countDone(nodes)
	pct := (done * 100) / len(nodes)
	return fmt.Sprintf("width: %d%%", pct)
}

func countDone(nodes []Node) int {
	n := 0
	for _, nd := range nodes {
		if nd.State == StateDone {
			n++
		}
	}
	return n
}

func truncate(s string, max int) string {
	if len(s) <= max {
		return s
	}
	return s[:max] + "…"
}

func lastMessageTS(messages []Node) string {
	if len(messages) == 0 {
		return time.Now().UTC().Format(time.RFC3339Nano)
	}
	return messages[len(messages)-1].CreatedAt.Format(time.RFC3339Nano)
}

